EPOXY_FILE = "vibrant-epoxy-colored-sand-durable-waterproof-for-crafts-decor.html"
WATERPROOF_FILE = "waterproof-coating-durable-weatherproof-for-indoor-outdoor-use.html"

EPOXY_FULL = f"https://pangugreen.com/{EPOXY_FILE}"
WATERPROOF_FULL = f"https://pangugreen.com/{WATERPROOF_FILE}"

# Override script to inject before </body>
OVERRIDE_SCRIPT = f"""<script>
(function() {{
    var URLS = {{
        '9988': '{EPOXY_FILE}',
        '10028': '{WATERPROOF_FILE}'
    }};

    // Remove wd-quick-shop class from our two product cards so quickShop.js ignores them
    function removeQuickShop() {{
        ['9988','10028'].forEach(function(id) {{
            var cards = document.querySelectorAll('[data-id="' + id + '"] .product-element-top');
            cards.forEach(function(el) {{
                el.classList.remove('wd-quick-shop');
            }});
        }});
    }}

    // Capturing click handler — runs before all jQuery/plugin handlers
    document.addEventListener('click', function(e) {{
        var card = e.target.closest('[data-id="9988"], [data-id="10028"]');
        if (!card) return;
        // Skip utility buttons: compare, wishlist, quick-view, swatch
        if (e.target.closest('.wd-compare-btn, .wd-wishlist-btn, .quick-view, .wd-swatch')) return;
        var id = card.getAttribute('data-id');
        var href = URLS[id];
        if (href) {{
            e.stopImmediatePropagation();
            e.preventDefault();
            window.location.href = href;
        }}
    }}, true);

    if (document.readyState === 'loading') {{
        document.addEventListener('DOMContentLoaded', removeQuickShop);
    }} else {{
        removeQuickShop();
    }}
}})();
</script>"""

for filename in ["product.html", "index.html"]:
    with open(filename, "r", encoding="utf-8") as f:
        content = f.read()

    original = content

    # --- FIX 1: Add product pages to the allowed list ---
    old_allowed = '["https://pangugreen.com/", "https://pangugreen.com/product.html", "https://pangugreen.com/about.html", "https://pangugreen.com/contact.html"]'
    new_allowed = f'["https://pangugreen.com/", "https://pangugreen.com/product.html", "https://pangugreen.com/about.html", "https://pangugreen.com/contact.html", "{EPOXY_FULL}", "{WATERPROOF_FULL}"]'
    content = content.replace(old_allowed, new_allowed)

    # --- FIX 2: Inject override script before </body> ---
    content = content.replace("</body></html>", OVERRIDE_SCRIPT + "\n</body></html>")

    if content != original:
        with open(filename, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"✓ {filename} patched")
    else:
        print(f"✗ {filename} — no change (strings not found)")

