<script>
/* ===================================================================
   PRODUCT VARIATION FIX — pangugreen.com static export
   Intercepts WooCommerce form submit & PayPal, redirects to checkout.html
   =================================================================== */
(function () {
    'use strict';

    /* ── Config ── */
    var PRODUCT    = 'epoxy';
    var ATTR_COLOR = 'attribute_pa_colors';   /* plural on this page */
    var ATTR_SIZE  = 'attribute_pa_size';
    var CHECKOUT   = './checkout.html';

    /* ── 1. Read active selections from <select> or from .wd-active swatch ── */
    function getSelections() {
        function readAttr(attrName) {
            /* 1a. Try the hidden <select> first (most reliable) */
            var sel = document.querySelector('select[name="' + attrName + '"]');
            if (sel && sel.value) return sel.value;
            /* 1b. Fall back to the visually-active swatch */
            var attrId  = attrName.replace(/^attribute_/, '');       /* e.g. "pa_colors" */
            var container = document.querySelector('.wd-swatches-product[data-id="' + attrId + '"]');
            if (container) {
                var active = container.querySelector('.wd-swatch.wd-active[data-value]');
                if (active) return active.getAttribute('data-value');
            }
            return '';
        }
        return {
            color : readAttr(ATTR_COLOR),
            size  : readAttr(ATTR_SIZE),
        };
    }

    /* ── 2. Sync .wd-active swatches → <select> values (fixes default pre-select) ── */
    function syncActiveSwatch(attrName) {
        var attrId    = attrName.replace(/^attribute_/, '');
        var container = document.querySelector('.wd-swatches-product[data-id="' + attrId + '"]');
        var sel       = document.querySelector('select[name="' + attrName + '"]');
        if (!container || !sel) return;
        var active = container.querySelector('.wd-swatch.wd-active[data-value]');
        if (active && active.getAttribute('data-value') && !sel.value) {
            sel.value = active.getAttribute('data-value');
        }
    }

    /* ── 3. On swatch click → update <select> (backup for Woodmart script) ── */
    function setupSwatchClickSync(attrName) {
        var attrId    = attrName.replace(/^attribute_/, '');
        var container = document.querySelector('.wd-swatches-product[data-id="' + attrId + '"]');
        var sel       = document.querySelector('select[name="' + attrName + '"]');
        if (!container || !sel) return;

        container.addEventListener('click', function (e) {
            var swatch = e.target.closest('.wd-swatch[data-value]');
            if (!swatch) return;
            /* Small timeout so Woodmart can apply .wd-active first */
            setTimeout(function () {
                var active = container.querySelector('.wd-swatch.wd-active[data-value]');
                sel.value = active ? active.getAttribute('data-value') : swatch.getAttribute('data-value');
            }, 30);
        });
    }

    /* ── 4. Show inline error inside WooCommerce variation area ── */
    function showError(msg) {
        var area = document.querySelector('.woocommerce-variation.single_variation');
        if (!area) return;
        area.innerHTML = '<p style="color:#c0392b;background:#fdf0ef;border:1px solid #f5c6c6;border-radius:5px;padding:9px 14px;margin:8px 0;font-size:14px;font-family:Jost,sans-serif">' + msg + '</p>';
    }

    /* ── 5. Build checkout URL and redirect ── */
    function goCheckout(sel) {
        var p = new URLSearchParams();
        p.set('product', PRODUCT);
        if (sel.color) p.set('color', sel.color);
        if (sel.size)  p.set('size',  sel.size);
        window.location.href = CHECKOUT + '?' + p.toString();
    }

    /* ── 6. Intercept FORM SUBMIT — capture phase (runs before WooCommerce) ── */
    document.addEventListener('submit', function (e) {
        var form = e.target;
        if (!form || !form.classList.contains('variations_form')) return;

        /* Always prevent WooCommerce's default AJAX/POST to the WP backend */
        e.preventDefault();
        e.stopImmediatePropagation();

        /* Re-sync swatches in case Woodmart script ran between page load and click */
        syncActiveSwatch(ATTR_COLOR);
        syncActiveSwatch(ATTR_SIZE);

        var sel = getSelections();

        if (!sel.color && !sel.size) {
            showError('Please choose a <strong>Color</strong> and <strong>Size</strong> before continuing.');
            return;
        }
        if (!sel.color) {
            showError('Please choose a <strong>Color</strong> before continuing.');
            return;
        }
        if (!sel.size) {
            showError('Please choose a <strong>Size</strong> before continuing.');
            return;
        }

        goCheckout(sel);
    }, true /* capture */);

    /* ── 7. Intercept BUY NOW button click directly (extra safety) ── */
    document.addEventListener('click', function (e) {
        var btn = e.target.closest('.wd-buy-now-btn, .single_add_to_cart_button');
        if (!btn) return;
        if (!btn.closest('.variations_form')) return;

        syncActiveSwatch(ATTR_COLOR);
        syncActiveSwatch(ATTR_SIZE);

        var sel = getSelections();

        if (!sel.color || !sel.size) {
            e.preventDefault();
            e.stopImmediatePropagation();
            if (!sel.color && !sel.size) showError('Please choose a <strong>Color</strong> and <strong>Size</strong> before continuing.');
            else if (!sel.color) showError('Please choose a <strong>Color</strong> before continuing.');
            else showError('Please choose a <strong>Size</strong> before continuing.');
            return;
        }
        /* If valid, let the form submit handler above handle the redirect */
    }, true /* capture */);

    /* ── 8. Replace the WooCommerce PayPal Express buttons ──
       They call the WP backend (?wc-ajax=ppc-create-order) which is unavailable
       in a static export. Replace with a helpful nudge to use our checkout.    ── */
    function replacePayPalBlock() {
        var wrapper = document.querySelector('.ppc-button-wrapper');
        if (wrapper && !wrapper.getAttribute('data-fixed')) {
            wrapper.setAttribute('data-fixed', '1');
            wrapper.innerHTML =
                '<div style="border:1px solid #e8f0e6;border-radius:8px;padding:12px 16px;text-align:center;background:#f9fcf8;font-family:Jost,sans-serif;font-size:13px;color:#555;margin-top:4px">' +
                '<svg style="vertical-align:middle;margin-right:6px;color:#2d5a27" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>' +
                'Select your options above, then click <strong>Add to cart</strong> or <strong>Buy now</strong> — PayPal is available on our secure checkout page.' +
                '</div>';
        }
        var msgs = document.querySelector('.ppcp-messages');
        if (msgs) msgs.style.display = 'none';
    }

    /* ── Boot ── */
    function boot() {
        syncActiveSwatch(ATTR_COLOR);
        syncActiveSwatch(ATTR_SIZE);
        setupSwatchClickSync(ATTR_COLOR);
        setupSwatchClickSync(ATTR_SIZE);
        replacePayPalBlock();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', boot);
    } else {
        boot();
    }
    /* Re-run after deferred scripts (PayPal SDK, Woodmart) finish loading */
    setTimeout(replacePayPalBlock, 800);
    setTimeout(replacePayPalBlock, 2000);
})();

        }, true);
    });
})();
